exemplos.python:
while True:
    print("1 - Marcar Ponto | 2 - Pedir Pausa | 0 - Sair")
    opcao = input("Opção: ")

    if opcao == "1":
        print("Ponto registrado com sucesso.")
    elif opcao == "2":
        print("Pausa autorizada.")
    elif opcao == "0":
        print("Sistema encerrado.")
        break
    else:
        print("Ação inválida. Tente novamente.")

pratica_guiada.python:
# O programa entra num estado de alerta e verificação constante
while True:
    peso_peca = float(input("Digite o peso da peça verificada: "))

    if peso_peca == 10.0:
        print("Peça aprovada. Seguindo para a embalagem.")
        break # O trabalho de validação terminou com sucesso
    else:
        print("Peça com defeito! Recusada. Verifique a próxima.")

# Este código só será executado quando a peça perfeita aparecer e o break for acionado
print("Validação do lote finalizada.")
